const row = $input.first()?.json || {};
const checkoutUrl = row.checkout_url || '';
const txnId = row.paddle_transaction_id || '';
const paddleBaseUrl = ($env.PADDLE_API_URL || '').includes('sandbox')
  ? 'https://sandbox-buy.paddle.com'
  : 'https://buy.paddle.com';
const fallbackUrl = txnId ? `${paddleBaseUrl}/checkout/${txnId}` : '';
const finalUrl = checkoutUrl || fallbackUrl;
return [{
  json: {
    redirect_url: finalUrl || 'https://www.microdosing-training.com/payment-error?reason=missing_checkout'
  }
}];
